async (page) => {
  const result = await page.evaluate(() => {
    // Use state extractor click coords for nearest rat
    const s = window.__latestGameState;
    const rats = (s.nearby_entities || []).filter(e => e.type === 3 && e.name === 'Rat' && e.on_screen && e.click_x != null);
    if (rats.length === 0) return { error: 'no on-screen rats', nearby: (s.nearby_entities||[]).slice(0,5).map(e=>e.name) };
    const rat = rats[0];
    // Set attack target
    const entities = Object.values(window.game.entities.entities || {});
    const mob = entities.find(e => e.gridX === rat.x && e.gridY === rat.y);
    if (mob) window.game.input.setAttackTarget(mob);
    // Click
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: rat.click_x, clientY: rat.click_y, bubbles: true, ctrlKey: false }));
    return { attacking: rat.name, cx: rat.click_x, cy: rat.click_y, pos: {x: rat.x, y: rat.y} };
  });
  await page.waitForTimeout(7000);
  return JSON.stringify(result);
}

async (page) => {
  for (let i = 0; i < 5; i++) {
    const killed = await page.evaluate(() => {
      const s = window.__latestGameState;
      // Try rats first, then any on-screen mob
      const mobs = (s.nearby_entities || []).filter(e => e.type === 3 && e.on_screen && e.click_x != null && e.name === 'Rat');
      if (mobs.length === 0) return null;
      const mob = mobs[0];
      const entities = Object.values(window.game.entities.entities || {});
      const target = entities.find(e => e.gridX === mob.x && e.gridY === mob.y);
      if (target) window.game.input.setAttackTarget(target);
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('click', { clientX: mob.click_x, clientY: mob.click_y, bubbles: true, ctrlKey: false }));
      return { name: mob.name, pos: {x: mob.x, y: mob.y} };
    });
    if (!killed) {
      // No on-screen rats - walk toward rat zone
      await page.evaluate(() => window.__clickTile(185, 159));
      await page.waitForTimeout(3000);
      continue;
    }
    await page.waitForTimeout(7000);
    const hp = await page.evaluate(() => {
      const s = window.__latestGameState;
      return { hp: s.player_stats.hp, max_hp: s.player_stats.max_hp, dead: s.ui_state.is_dead };
    });
    if (hp.dead) break;
    if (hp.hp < 50) {
      // Eat burger
      await page.evaluate(() => window.game.menu.getInventory().selectEdible(0));
      await page.waitForTimeout(1000);
    }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const totalXP = window.game.player.getTotalExperience();
    const str = window.game.player.skills[6];
    return {
      pos: s.player_position,
      hp: s.player_stats.hp, max_hp: s.player_stats.max_hp,
      level: s.player_stats.level, totalXP,
      str_level: str ? str.level : 0, str_xp: str ? str.experience : 0,
      is_dead: s.ui_state.is_dead,
      inv: s.inventory.map(i => i.name)
    };
  });
  return JSON.stringify(state);
}

