async (page) => {
  // Find and chop oak trees to get 4 more logs
  let logsGained = 0;

  for (let i = 0; i < 6 && logsGained < 4; i++) {
    const treeResult = await page.evaluate(() => {
      const s = window.__latestGameState;
      // Find on-screen oak trees
      const trees = (s.nearby_entities || []).filter(e => e.name === 'Oak' && e.on_screen && e.click_x != null);
      if (trees.length === 0) return null;
      const tree = trees[0];
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('click', { clientX: tree.click_x, clientY: tree.click_y, bubbles: true, ctrlKey: false }));
      return { tree: tree.name, pos: {x: tree.x, y: tree.y} };
    });

    if (!treeResult) {
      // Walk to a known tree area
      await page.evaluate(() => window.__clickTile(214, 118));
      await page.waitForTimeout(3000);
      continue;
    }

    await page.waitForTimeout(5000);

    const logCount = await page.evaluate(() => {
      const s = window.__latestGameState;
      return (s.inventory||[]).filter(i => i.name === 'Logs').length;
    });
    logsGained = logCount - 6; // We started with 6
  }

  const finalCount = await page.evaluate(() => {
    const s = window.__latestGameState;
    const lumberjack = window.game.player.skills[0];
    return {
      logs: (s.inventory||[]).filter(i => i.name === 'Logs').length,
      total_inv: s.inventory.length,
      lumberjack_level: lumberjack ? lumberjack.level : 0,
      lumberjack_xp: lumberjack ? lumberjack.experience : 0,
      pos: s.player_position
    };
  });
  return JSON.stringify(finalCount);
}

