async (page) => {
  const result = await page.evaluate(() => {
    const map = window.game.map;
    const player = window.game.player;
    const startX = player.gridX, startY = player.gridY;
    const goalX = 137, goalY = 171;

    const visited = new Map();
    const queue = [[startX, startY]];
    visited.set(`${startX},${startY}`, null);
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    let found = false;
    let iterations = 0;

    while (queue.length > 0 && iterations < 30000) {
      iterations++;
      const [x, y] = queue.shift();
      if (x === goalX && y === goalY) { found = true; break; }
      for (const [dx, dy] of dirs) {
        const nx = x+dx, ny = y+dy;
        const key = `${nx},${ny}`;
        if (visited.has(key)) continue;
        if (map.isColliding(nx, ny)) continue;
        visited.set(key, `${x},${y}`);
        queue.push([nx, ny]);
      }
    }

    if (!found) return JSON.stringify({found: false, iterations, visited: visited.size});

    const path = [];
    let curr = `${goalX},${goalY}`;
    while (curr) {
      const [x, y] = curr.split(',').map(Number);
      path.unshift([x, y]);
      curr = visited.get(curr);
    }

    // Waypoints every 20 steps
    const waypoints = path.filter((_, i) => i % 20 === 0 || i === path.length - 1);
    return JSON.stringify({found, pathLen: path.length, waypoints});
  });
  return result;
}

