async (page) => {
  const result = await page.evaluate(() => {
    const map = window.game.map;
    const player = window.game.player;
    const startX = player.gridX, startY = player.gridY;

    // BFS to find nearby reachable tiles
    const visited = new Set();
    const queue = [[startX, startY]];
    visited.add(`${startX},${startY}`);
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    let iterations = 0;

    while (queue.length > 0 && iterations < 3000) {
      iterations++;
      const [x, y] = queue.shift();
      for (const [dx, dy] of dirs) {
        const nx = x+dx, ny = y+dy;
        const key = `${nx},${ny}`;
        if (visited.has(key)) continue;
        if (map.isColliding(nx, ny)) continue;
        visited.set ? visited.set(key) : visited.add(key);
        queue.push([nx, ny]);
      }
    }

    const tiles = [...visited].map(k => k.split(',').map(Number));
    const minX = Math.min(...tiles.map(t => t[0]));
    const maxX = Math.max(...tiles.map(t => t[0]));
    const minY = Math.min(...tiles.map(t => t[1]));
    const maxY = Math.max(...tiles.map(t => t[1]));

    // Check if Royal Guard tile is reachable
    const guardReachable = visited.has('282,887');

    return JSON.stringify({count: visited.size, minX, maxX, minY, maxY, guardReachable, start: {startX, startY}});
  });
  return result;
}

