async (page) => {
  // BFS to Odd-Eyed Cat at (111, 149)
  const pathResult = await page.evaluate(() => {
    const map = window.game.map;
    const player = window.game.player;
    const sx = player.gridX, sy = player.gridY;
    const gx = 112, gy = 149;

    const visited = new Map();
    const queue = [[sx, sy]];
    visited.set(`${sx},${sy}`, null);
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    let found = false;

    while (queue.length > 0) {
      const [x,y] = queue.shift();
      if (x===gx && y===gy) { found=true; break; }
      for (const [dx,dy] of dirs) {
        const nx=x+dx, ny=y+dy, key=`${nx},${ny}`;
        if (visited.has(key) || map.isColliding(nx,ny)) continue;
        visited.set(key, `${x},${y}`);
        queue.push([nx, ny]);
      }
    }

    if (!found) return {found: false};
    const path = [];
    let cur = `${gx},${gy}`;
    while(cur) { path.unshift(cur.split(',').map(Number)); cur=visited.get(cur); }
    return {found: true, pathLen: path.length, waypoints: path.filter((_,i)=>i%20===0||i===path.length-1)};
  });

  if (!pathResult.found) return 'No path found';

  for (const [x,y] of pathResult.waypoints.slice(1)) {
    await page.evaluate(({x,y}) => window.game.player.go(x,y), {x,y});
    await page.waitForTimeout(7000);
  }

  const pos = await page.evaluate(() => ({x: window.game.player.gridX, y: window.game.player.gridY}));

  // Talk to Odd-Eyed Cat
  const dialogues = [];
  for (let i = 0; i < 8; i++) {
    await page.evaluate(() => window.__talkToNPC('1-78797353'));
    await page.waitForTimeout(1500);
    const gs = await page.evaluate(() => window.__latestGameState);
    const d = gs?.ui_state?.npc_dialogue;
    const qp = gs?.ui_state?.quest_panel_visible;
    if (d && !dialogues.includes(d)) dialogues.push(d);
    else if (!d && i > 0) break;
    if (qp) {
      await page.evaluate(() => document.getElementById('quest-button')?.click());
      await page.waitForTimeout(1000);
      dialogues.push('QUEST PANEL CLICKED');
      break;
    }
  }

  return JSON.stringify({pos, waypoints: pathResult.waypoints, dialogues});
}

