async (page) => {
  // BFS from current position to village area near (136, 140)
  const pathResult = await page.evaluate(() => {
    const map = window.game.map;
    const startX = window.game.player.gridX, startY = window.game.player.gridY;
    const goalX = 136, goalY = 140;
    const visited = new Map();
    const queue = [[startX, startY]];
    visited.set(`${startX},${startY}`, null);
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    let found = false, iterations = 0;
    while (queue.length > 0 && iterations < 300000) {
      iterations++;
      const [x,y] = queue.shift();
      if (x === goalX && y === goalY) { found = true; break; }
      for (const [dx,dy] of dirs) {
        const nx = x+dx, ny = y+dy;
        const key = `${nx},${ny}`;
        if (visited.has(key) || map.isColliding(nx, ny)) continue;
        visited.set(key, `${x},${y}`);
        queue.push([nx, ny]);
      }
    }
    if (!found) return { found: false, iterations };
    const path = [];
    let cur = `${goalX},${goalY}`;
    while (cur) { path.unshift(cur.split(',').map(Number)); cur = visited.get(cur); }
    const waypoints = path.filter((_,i) => i % 15 === 0 || i === path.length - 1);
    return { found, pathLen: path.length, waypoints, iterations };
  });
  return JSON.stringify(pathResult);
}

