async (page) => {
  // Set up teleport detection
  await page.evaluate(() => {
    window.__teleportLog = [];
    window.__teleportDetected = false;
    const proto = Object.getPrototypeOf(window.game.socket.messages);
    if (!proto.__teleportPatched) {
      proto.__teleportPatched = true;
      const oT = proto.onTeleport;
      proto.onTeleport = function(...a) {
        window.__teleportLog.push({args: JSON.stringify(a).slice(0, 300)});
        window.__teleportDetected = true;
        return oT.apply(this, a);
      };
    }
  });

  // Try beach portal at (205, 730)
  await page.evaluate(() => {
    window.__teleportDetected = false;
    window.game.player.go(205, 730);
  });
  await page.waitForTimeout(5000);

  const state = await page.evaluate(() => ({
    teleported: window.__teleportDetected,
    pos: {x: window.game.player.gridX, y: window.game.player.gridY},
    logs: window.__teleportLog
  }));

  // If not teleported, try (161, 730)
  if (!state.teleported && state.pos.x === 205 && state.pos.y === 730) {
    await page.evaluate(() => {
      window.__teleportDetected = false;
