async (page) => {
  // BFS navigate to Cat at (111, 149)
  const path = await page.evaluate(({goalX, goalY}) => {
    const map = window.game.map;
    const sx = window.game.player.gridX, sy = window.game.player.gridY;
    const visited = new Map();
    const queue = [[sx, sy]];
    visited.set(`${sx},${sy}`, null);
    const dirs = [[0,1],[0,-1],[1,0],[-1,0]];
    const portals = new Set(['181,157','123,205','136,170','184,116','329,898']);
    let found = false;
    while (queue.length > 0) {
      const [x,y] = queue.shift();
      if (x===goalX && y===goalY) {found=true; break;}
      for (const [dx,dy] of dirs) {
        const nx=x+dx, ny=y+dy, key=`${nx},${ny}`;
        if (visited.has(key)||map.isColliding(nx,ny)||portals.has(key)) continue;
        visited.set(key, `${x},${y}`);
        queue.push([nx,ny]);
      }
    }
    if (!found) return null;
    const p = [];
    let cur = `${goalX},${goalY}`;
    while(cur) { p.unshift(cur.split(',').map(Number)); cur=visited.get(cur); }
    return p.filter((_,i)=>i%8===0||i===p.length-1);
  }, {goalX: 112, goalY: 149}); // adjacent to cat

  if (!path) return 'no path';
  for (const [x, y] of path) {
    await page.evaluate(({x,y}) => window.__clickTile(x,y), {x,y});
    await page.waitForTimeout(2500);
  }

  const pos = await page.evaluate(() => ({x: window.game.player.gridX, y: window.game.player.gridY}));

  // Talk to cat
  const dialogues = [];
  for (let i = 0; i < 6; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), '1-78797353');
    await page.waitForTimeout(800);
    const d = await page.evaluate(() => window.__latestGameState?.ui_state?.npc_dialogue);
    if (d && !dialogues.includes(d)) dialogues.push(d);
  }
  return JSON.stringify({pos, dialogues});
}

