async (page) => {
  const info = await page.evaluate(() => {
    const w = window.game.menu.warp;

    // Get list items data
    const listData = [];
    if (w.list) {
      for (let i = 0; i < 6; i++) {
        const item = w.list[i];
        if (item) {
          listData.push({
            index: i,
            type: typeof item,
            keys: typeof item === 'object' ? Object.keys(item) : [],
            tagName: item.tagName,
            id: item.id,
            dataset: item.dataset ? Object.fromEntries(Object.entries(item.dataset)) : null
          });
        }
      }
    }

    // Also check the warp's send method or any send-like function
    const warpSendKeys = Object.keys(w).filter(k => typeof w[k] === 'function');

    // Try to intercept: temporarily replace selectCallback to see what it receives
    const origCallback = w.selectCallback;
    let capturedArgs = null;
    w.selectCallback = function(...args) {
      capturedArgs = args;
      w.selectCallback = origCallback; // restore
      return origCallback?.apply(this, args);
    };

    // Click warp0 to trigger the callback
    document.getElementById('warp0').click();

    return {listData, warpSendKeys, capturedArgs};
  });

  await page.waitForTimeout(2000);

  const pos = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {x: gs.player_position.x, y: gs.player_position.y};
  });

  return JSON.stringify({info, pos});
}

