async (page) => {
  // Click on Guard entity - they're visible on screen
  const result = await page.evaluate(() => {
    // Find Guard in entities
    const entities = window.__latestGameState?.nearby_entities;
    const guard = entities?.find(e => e.name === 'Guard' && e.type === 1);
    if (guard && guard.on_screen) {
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('click', {clientX: guard.click_x, clientY: guard.click_y, bubbles: true, ctrlKey: false}));
      return {clicked: guard.name, click_x: guard.click_x, click_y: guard.click_y};
    }
    return {error: 'Guard not found or off screen'};
  });
  await page.waitForTimeout(3000);
  const pos = await page.evaluate(() => ({x: window.game.player.gridX, y: window.game.player.gridY}));
  const dialogue = await page.evaluate(() => window.__latestGameState?.ui_state?.npc_dialogue);
  const guardId = await page.evaluate(() => {
    const e = window.__latestGameState?.nearby_entities?.find(e => e.name === 'Guard');
    return e?.id;
  });
  return JSON.stringify({clickResult: result, pos, dialogue, guardId});
}

