  await page.evaluate(() => window.game.player.setAttackStyle(0));

  // Get full game state
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const data = JSON.parse(state);

  const result = {
    pos: data.player_position,
    stats: data.player_stats,
    skills: data.skills,
    equip: data.equipment,
    ui: data.ui_state,
    inv: data.inventory?.filter(i => i.equippable || i.edible || i.name?.includes('Quest'))
  };
