async (page) => {
  const result = await page.evaluate(() => {
    const p = window.game?.player;
    if (!p) return { error: 'no player' };
    return {
      weapon: p.equipments?.weapon?.key || p.weaponKey || 'none',
      skills: {
        Str: p.skills?.Strength?.level || p.skills?.strength?.level,
        Def: p.skills?.Defense?.level || p.skills?.defense?.level,
      },
      allEquip: p.equipments ? Object.entries(p.equipments).map(([k,v]) => ({slot: k, key: v?.key})) : 'no equipments'
    };
  });
  const ascii = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    if (!m || m.error) return 'no map';
    return m.ascii.split('\n').slice(0, 20).join('\n') + '\n\n' + m.legendText.slice(0, 500);
  });
  return JSON.stringify(result) + '\n\nASCII:\n' + ascii;
}
